// all functions below are a WIP

uint8_t oam_buffer_handler(uint8_t de, uint8_t *p_de, uint8_t stored_de, uint16_t hl) {
    uint16_t *p_hl = &hl;
    
    uint8_t loop_counter = stored_de & 0x3F;    // 0011 1111: 63 max

    stored_de <<= 2; // Rotate left + carry <- implement carry
    stored_de &= 3;

    if (stored_de == 0) {
        while (loop_counter != 0) {
            *p_hl = *p_de;

            hl++;
            de++;

            loop_counter--;
        }

        return 0;
    }

    stored_de--;

    if (stored_de == 0) {
        stored_de = *p_de;
        de++;

        // Lab_02e3:
        while (loop_counter != 0) {
            *p_hl = stored_de;

            hl++;
            loop_counter--;
        }

        return 0;
    }

    stored_de--;

    if (stored_de == 0) {
        while (loop_counter != 0) {
            *p_hl = *p_de;

            de++;
            hl += 32;
            loop_counter--;
        }

        return 0;
    }

    while (loop_counter != 0) {
        *p_hl = *p_de;

        hl += 32;
        loop_counter--;
    }

    de++;
    return 0;
}

uint8_t copy_oam_buffer_to_hl(uint8_t de, uint8_t *p_de) {
    uint16_t hl = (*p_de << 8);

    de++;
    hl += *p_de;

    de++;
    uint8_t stored_de = de;

    de++;

    oam_buffer_handler(de, p_de, stored_de, hl);
}

uint8_t is_oam_buffer_empty(uint8_t *p_de, uint8_t de) {
    if (*p_de != 0)
        copy_oam_buffer_to_hl(de, p_de);
}

void oam_buffer_update(void) {
    if (hram.object_dirty_flag != 0) {
        // uint8_t tile = wram.tile_buffer[0];
        // uint8_t *ptile = &tile;

        uint8_t de = wram.tile_buffer[0];
        uint8_t *p_de = &de;

        is_oam_buffer_empty(p_de, de);

        wram.bg_map_buffer_pad = 0;
        wram.tile_buffer[0] = 0;
        hram.object_dirty_flag = false;
    }
}